VALUES
  ('heelevel3-988e0de1-moex-00149', 'heelevel3-988e0de1', 'heelevel3-988e0de1-moex-110-ac2adf20', 'sub-heelevel3-988e0de1-02', NULL, 'single_choice', '依中央政府普通公務單位會計制度之一致規定，X1年12月4日中央政府A機關撥款給甲直轄市 政府B機關，補助辦理X2年度博物館興建計畫，此時尚未符合中央政府A機關所規定應列入其 地方預算之條件；嗣甲直轄市政府B機關將補助收入列入X2年度地方預算，但未經市議會審查 通過，X2年退還補助收入應作之分錄為何？', '["借：補助收入，貸：繳付公庫數", "借：補助收入，貸：專戶存款", "借：預收其他政府款，貸：繳付公庫數", "借：預收其他政府款，貸：專戶存款"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:27+00:00", "source_pdf_sha1": "dcb3276a8393", "answer_pdf_sha1": "807ca00816e0", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "326", "s": "1109", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "政府會計", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財務審計"}'::jsonb, NULL),
  ('heelevel3-988e0de1-moex-00150', 'heelevel3-988e0de1', 'heelevel3-988e0de1-moex-110-ac2adf20', 'sub-heelevel3-988e0de1-02', NULL, 'single_choice', '依中央政府普通公務單位會計制度之一致規定，提出作保證用之款項，屬於那一類的會計項目？', '["資產", "負債", "收入", "支出"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:27+00:00", "source_pdf_sha1": "dcb3276a8393", "answer_pdf_sha1": "807ca00816e0", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "326", "s": "1109", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "政府會計", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財務審計"}'::jsonb, NULL),
  ('heelevel3-988e0de1-moex-00151', 'heelevel3-988e0de1', 'heelevel3-988e0de1-moex-110-ac2adf20', 'sub-heelevel3-988e0de1-02', NULL, 'single_choice', '乙機關簽訂租賃契約，自108年1 月1日起向A公司租用全新的電腦設備，租期4年，每年1月 1日給付租金30萬元，租期屆滿時，乙機關得以選擇以2萬元購買。又該設備原定耐用年限5年， 估計殘值為10萬元，108年1月1日評定之公允價值為120萬元，有效利率為1.5%（3年期複利 現值0.956、3年期年金現值2.912；4年期複利現值0.942、4年期年金現值3.854），則108年12 月31日記載之其他利息金額為何？', '["1.7887萬元", "1.3387萬元", "1.3126萬元", "1.3104萬元"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:27+00:00", "source_pdf_sha1": "dcb3276a8393", "answer_pdf_sha1": "807ca00816e0", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "326", "s": "1109", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "政府會計", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財務審計"}'::jsonb, NULL),
  ('heelevel3-988e0de1-moex-00152', 'heelevel3-988e0de1', 'heelevel3-988e0de1-moex-110-ac2adf20', 'sub-heelevel3-988e0de1-02', NULL, 'single_choice', '依中央政府普通公務單位會計制度之一致規定，A國營事業盈餘繳庫時，其主管機關應貸記那個 會計科目？', '["採權益法之投資", "採權益法之投資評價調整", "營業基金繳庫盈餘", "繳付公庫數"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:27+00:00", "source_pdf_sha1": "dcb3276a8393", "answer_pdf_sha1": "807ca00816e0", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "326", "s": "1109", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "政府會計", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財務審計"}'::jsonb, NULL),
  ('heelevel3-988e0de1-moex-00153', 'heelevel3-988e0de1', 'heelevel3-988e0de1-moex-110-ac2adf20', 'sub-heelevel3-988e0de1-02', NULL, 'single_choice', '中央政府公務機關甲機關，前撥款1,000萬元作為資本，創設一非公司組織的國營事業，該事業已 連續數年虧損，但X1年底甲機關帳列採權益法之投資帳列1,000萬元，以及採權益法之投資評價 調整（借餘）450萬元。X3年1月1日該事業改制為非公開發行公司，登記資本額為1,400萬元 （140萬股，每股面額10元），未對外募資。X3年度，甲機關貸記「採權益法之投資評價調整」100 萬元，X4及X5年底再分別貸記「採權益法之投資評價調整」400萬元及200萬元，但X6年底， 甲機關「採權益法之投資評價調整」科目餘額反而為借餘400萬元。下列敘述何者錯誤？', '["甲機關採權益法之投資評價調整連續3年於貸方認列，顯示改制公司之事業仍然處於虧損狀態", "X6年底甲機關採權益法之投資評價調整科目轉為借餘，顯示可能有大筆業外收益入帳", "該事業改制公司時，無須認列資本公積—股本溢價", "X5年底甲機關採權益法之投資評價調整科目餘額為貸餘"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:27+00:00", "source_pdf_sha1": "dcb3276a8393", "answer_pdf_sha1": "807ca00816e0", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "326", "s": "1109", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "政府會計", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財務審計"}'::jsonb, NULL),
  ('heelevel3-988e0de1-moex-00154', 'heelevel3-988e0de1', 'heelevel3-988e0de1-moex-110-ac2adf20', 'sub-heelevel3-988e0de1-02', NULL, 'single_choice', '甲機關於X1年度自行開發設計資訊安全管理及控制系統，預計使用10年。X1年度投入之經費 包括人事費及業務費共100萬元，以及於1月1日購入之專利技術使用權30萬元（專利使用期 限15年，只能用於上述系統，殘值3萬元）。另為應系統開發及驗測需要，甲機關將1月1日新 購的伺服器1部60萬元（耐用年限5年，無殘值），並作為系統的伺服器。上述系統於X1年底 完成開發，X2年1月1日上線使用。參照政府會計準則公報第5號規定，甲機關X2年度開始時 應認列的電腦軟體成本為何？', '["190萬元", "139萬2千元", "130萬元", "128萬2千元"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:27+00:00", "source_pdf_sha1": "dcb3276a8393", "answer_pdf_sha1": "807ca00816e0", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "326", "s": "1109", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "政府會計", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財務審計"}'::jsonb, NULL),
  ('heelevel3-988e0de1-moex-00155', 'heelevel3-988e0de1', 'heelevel3-988e0de1-moex-110-ac2adf20', 'sub-heelevel3-988e0de1-02', NULL, 'single_choice', '依中央政府普通公務單位會計制度之一致規定，甲機關收到公庫撥款支應工作計畫之款項，下列敘', '["應認列為收入", "應認列為支出", "應貸記公庫撥入數", "應借記各機關現金"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:27+00:00", "source_pdf_sha1": "dcb3276a8393", "answer_pdf_sha1": "807ca00816e0", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "326", "s": "1109", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "政府會計", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 16, "answer_corrected": true, "flags": ["answer_corrected_skip_v1"], "civil_slug": "heelevel3", "civil_category": "財務審計"}'::jsonb, NULL),
