  ('heelevel3-988e0de1-moex-00157', 'heelevel3-988e0de1', 'heelevel3-988e0de1-moex-110-ac2adf20', 'sub-heelevel3-988e0de1-02', NULL, 'single_choice', '依政府會計準則公報第1號規定，支出（或費損）係指一會計期間內經濟效益的減少，下列敘述 何者錯誤？', '["公務機關之支出，尚包括解繳公庫造成財務資源之流出部分", "有關經濟效益的減少係指資產流出、消耗或負債減少等方式，造成淨資產之減少", "將單位會計彙編為總會計時，各公務機關認列繳付公庫數之支出，應與國庫所經收之收入款項 相互沖抵為零", "各項週期性支出，法令規定有支付時期者，於支付時，始認列支出"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:27+00:00", "source_pdf_sha1": "dcb3276a8393", "answer_pdf_sha1": "807ca00816e0", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "326", "s": "1109", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "政府會計", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財務審計"}'::jsonb, NULL),
  ('heelevel3-988e0de1-moex-00158', 'heelevel3-988e0de1', 'heelevel3-988e0de1-moex-110-ac2adf20', 'sub-heelevel3-988e0de1-02', NULL, 'single_choice', '依政府會計準則公報規定，政府財務報表要素認列必須符合之要件為何？①符合定義  ②可了解', '["未來經濟效益的可能性", "衡量的可靠性", "僅", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:27+00:00", "source_pdf_sha1": "dcb3276a8393", "answer_pdf_sha1": "807ca00816e0", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "326", "s": "1109", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "政府會計", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 19, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "heelevel3", "civil_category": "財務審計"}'::jsonb, NULL)
